PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?character ?characterLabel WHERE {
  VALUES ?franchise {
    wd:Q642878
  }
  .
  VALUES ?workType {
    wd:Q11424 wd:Q5398426
  }
  .
  ?work wdt:P179 ?franchise ; wdt:P31 ?workType ; wdt:P674 ?character .
  ?character wdt:P21 wd:Q6581097 .
  ?character rdfs:label ?characterLabel .
  FILTER(LANG(?characterLabel) = "en")
}
